SELECT period_id, SUM(total_value) AS total_trade_value, AVG(average_value_per_unit) AS average_value
FROM trade_statistics
GROUP BY period_id;

SELECT total_value, average_value_per_unit
FROM trade_statistics
WHERE period_id = 1;

SELECT average_value_per_unit
FROM trade_statistics
WHERE period_id = 1;

SELECT AVG(rate) AS average_conversion_rate
FROM currency_conversion_rates
WHERE currency_code = 'GBP';
